INSERT INTO `lareja_web_event` VALUES (1,'Estacional de Primavera','Sábado 26 de Septiembre','Las Estacionales son celebraciones en las que nos encontramos para compartir un ámbito profundo. Hacemos ceremonias, intercambios, talleres, presentaciones y muchas actividades más. También aprovechamos para reencontrarnos con amigos.\r\n\r\nEn esta oportunidad, dada la situación que todos conocemos, nos encontraremos virtualmente. ¡Bienvenidos!','Si querés agregar una nueva actividad comunicate con fercon@gmail.com\r\n\r\nSolicitá los datos de acceso a cada sala a la persona que figura en cada evento.','2020-09-14 01:58:33','2020-09-14 01:58:33',NULL,'');
