o'),(11,1161,'[{\"lang\":\"es\",\"name\":\"Informe sobre Nuevos Procesos\",\"file\":\"alejandro-roger_informe-sobre-nuevos-procesos.pdf\"}]','2018-11-05 01:24:50','2018-11-05 01:32:31','2018-11-05 01:32:31','o'),(12,1161,'[{\"lang\":\"es\",\"name\":\"La Experiencia de Fuerza y la Acci\\u00f3n en el Mundo\",\"file\":\"alejandro-roger_la-experiencia-de-fuerza-y-la-accion-en-el-mundo.pdf\"}]','2018-11-05 01:24:50','2018-11-05 01:32:31','2018-11-05 01:32:31','o'),(13,1161,'[{\"lang\":\"es\",\"name\":\"Ser de Luz\",\"file\":\"alejandro-roger_ser-de-luz.pdf\"}]','2018-11-05 01:24:50','2018-11-05 01:32:31','2018-11-05 01:32:31','o'),(14,979,'[{\"lang\":\"es\",\"name\":\"Disciplina Material - Estudio de su estructura interna\",\"file\":\"alejtman-ecicari-mmanzano_disciplina-material-su-estructura-interna.pdf\"}]','2018-11-05 01:24:50','2018-11-05 01:32:31','2018-11-05 01:32:31','m'),(15,1086,'[{\"lang\":\"es\",\"name\":\"El Budismo en Sri Lanka\",\"file\":\"alicia-ordonez_el-budismo-en-sri-lanka.pdf\"}]','2018-11-05 01:24:50','2018-11-05 01:32:31','2018-11-05 01:32:31','m'),(16,1086,'[{\"lang\":\"es\",\"name\":\"El Oscurecimiento del Ser en Occidente\",\"file\":\"alicia-ordonez_el-oscurecimiento-del-ser-en-occidente.pdf\"}]','2018-11-05 01:24:50','2018-11-05 01:32:31','2018-11-05 01:32:31','m'),(17,1104,'[{\"lang\":\"es\",\"name\":\"Mitos, algunos comentarios\",\"file\":\"andres-pellegrini_mitos-algunos-comentarios.pdf\"}]','2018-11-05 01:24:50','2018-11-05 01:32:31','2018-11-05 01:32:31','m'),(18,984,'[{\"lang\":\"es\",\"name\":\"El Vidrio en los Oficios del Fuego, Parte I\",\"file\":\"ariel-niro_el-vidrio-en-los-oficios-del-fuego-parte-1.pdf\"}]','2018-11-05 01:24:50','2018-11-05 01:32:31','2018-11-05 01:32:31','m'),(19,984,'[{\"lang\":\"es\",\"name\":\"El Vidrio en los Oficios del Fuego, Parte II\",\"file\":\"ariel-niro_el-vidrio-en-los-oficios-del-fuego-parte-2.zip\"}]','2018-11-05 01:24:50','2018-11-05 01:32:31','2018-11-05 01:32:31','m'),(20,1188,'[{\"lang\":\"es\",\"